import React, { useState } from "react";

export default function Judging() {
  const [formData, setFormData] = useState({
    creativity: "",
    craftsmanship: "",
    performance: "",
    overall: "",
  });
  const [submitted, setSubmitted] = useState(false);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const previous = JSON.parse(localStorage.getItem("judgingData")) || [];
    localStorage.setItem("judgingData", JSON.stringify([...previous, formData]));
    setSubmitted(true);
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Judging</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block">Creativity:</label>
          <input
            type="number"
            name="creativity"
            onChange={handleChange}
            required
            className="border rounded p-2 w-full"
          />
        </div>
        <div>
          <label className="block">Craftsmanship:</label>
          <input
            type="number"
            name="craftsmanship"
            onChange={handleChange}
            required
            className="border rounded p-2 w-full"
          />
        </div>
        <div>
          <label className="block">Performance:</label>
          <input
            type="number"
            name="performance"
            onChange={handleChange}
            required
            className="border rounded p-2 w-full"
          />
        </div>
        <div>
          <label className="block">Overall Impression:</label>
          <input
            type="number"
            name="overall"
            onChange={handleChange}
            required
            className="border rounded p-2 w-full"
          />
        </div>
        <button
          type="submit"
          className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700"
        >
          Bewertung absenden
        </button>
      </form>
      {submitted && (
        <div className="mt-4 p-4 bg-green-100 border border-green-500 text-green-700 rounded">
          Bewertung erfolgreich gespeichert!
        </div>
      )}
    </div>
  );
}
